        KUPOPOPO_THIS_IS_TERRIBLE_SOME_SNEAKY_SCOUNDRELS_HAVE                 = 7707,  -- Kupopopo`! This is terrible! Some sneaky scoundrels have swiped the armor we brought in for the Feast of Swords...again, kupo!
        AS_YOU_PROBABLY_ALREADY_KNOW_THE_VILLAINS_WEARING                     = 7708,  -- As you probably already know, the villains wearing the armor are invulnerable to normal weapons! And as if that wasn't enough, they're surrounded by a powerful aura that prevents them from being attacked at all, kupo!
        BUT_NEVER_FEAR_OUR_TOP_MOOGLE_RESEARCHERS_HAVE                        = 7709,  -- But never fear! Our top moogle researchers have created weapons that can injure these armor-thieving hooligans--the wondrous % and the marvelous %, kupo!
        THE_NOMAD_MOOGLES_HAVE_ALSO_DEVELOPED_A_MAGIC                         = 7710,  -- The nomad moogles have also developed a magic that will annul that anti-attack aura, so be sure to pay them a visit while wearing the weapon before you engage the enemy, kupo.
        BUT_BE_WARNED_THIS_MAGIC_HAS_THE_SIDE_2                               = 7711,  -- But be warned--this magic has the side effect of preventing you from attacking any other monster for three whole Vana'dielian days, kupo!
        AND_THAT_S_NOT_ALL_THIS_TIME_WE                                       = 7712,  -- And that's not all! This time we want to make sure that the wretched thieves have a hard time coming back, kupo!
        YOU_SEE_EVEN_IF_YOU_TAKE_ONE_OF                                       = 7713,  -- You see, even if you take one of them down, the power of the armor will slowly restore his health, and before you know it, the scoundrel will be back up to full health!
        THAT_S_WHY_WE_WANT_YOU_TO_PLANT                                       = 7714,  -- That's why we want you to plant (trade) your % or % into the ground near a fallen fiend. It will create a ward that should slow the equipment's regenerative properties, making it easier for you to defeat them again and again, kupo!
        JUST_REMEMBER_THAT_THE_FURTHER_AWAY_YOU_TRAVEL                        = 7715,  -- Just remember that the further away you travel from the ward, the weaker it becomes. We recommend staying in the same area for best results.
        ALRIGHT_HERE_S_YOUR_NOW_YOU_RE_READY                                  = 7716,  -- Alright. Here's your %. Now you're ready to do battle, kupo!
        OH_AND_YOU_LL_FIND_THAT_THE_PRIZES                                    = 7717,  -- Oh, and you'll find that the prizes we have for you this time are even better than the last ones. You might even be one of the lucky adventurers who wins a spiffy, new... Ah, you'll just have to see it to believe it, kupo!
        NOW_IF_YOU_WANT_TO_CROSS_SWORDS_WITH                                  = 7718,  -- Now, if you want to cross swords with the invincible interlopers, equip % or % and talk to a nomad moogle, kupo!
        VANA_DIEL_IS_UNDER_ATTACK_BY_VILLAINS_IN_3                            = 7719,  -- Vana'diel is under attack by villains in our stolen samurai armor! Help the moogles in each nation defeat this menace, kupo!
        WE_VE_MIXED_UP_SOME_MOOGLE_MAGIC_TO_3                                 = 7720,  -- We've mixed up some moogle magic to crack that aura, but you'll need to equip a special weapon to even cause a scratch, kupo! Equip, I tell you! Equiiiiiip!
        TH_THAT_IT_MAY_BE_JUST_THE_THING_3                                    = 7721,  -- Th-that %... It may be just the thing for whacking those wacky samurai! Hold still while I work my moogle magic, kupo!
        OH_JUST_DON_T_FORGET_TO_PLACE_THE                                     = 7722,  -- Oh, just don't forget to place the ward with your % when you've defeated one!
        YOU_LL_BE_ABLE_TO_REALLY_HURT_THOSE                                   = 7723,  -- You'll be able to really hurt those harbingers of harm with %. Now hold still while I work my moogle magic, kupo!
        OH_JUST_DON_T_FORGET_TO_PLACE_THE_2                                   = 7724,  -- Oh, just don't forget to place the ward with your % or your % when you've defeated one!
        AND_WHATEVER_YOU_DO_DON_T_WANDER_TOO                                  = 7725,  -- And whatever you do, don't wander too far from the area; your weary wards will weaken, kupo!
        NO_NO_NO_THAT_IS_WAY_TOO_SHARP                                        = 7726,  -- No, no, no! That % is way too sharp! Just think of the damage it will deal to the poor armor! Now go get yourself % or % and hurry back, kupo!
        WELL_DONE_ON_TO_THE_NEXT_ONE_KUPO                                     = 7727,  -- Well done! On to the next one, kupo!
        THAT_THIEF_HAS_ALREADY_BEEN_WEAKENED_BY_A                             = 7728,  -- That thief has already been weakened by a ward. Try to find one that hasn't, kupo!
        WONDERFUL_HERE_S_YOUR_REWARD_KUPO_IF_YOU                              = 7729,  -- Wonderful! Here's your reward, kupo! If you're still up for it, why don't you go out and whack yourself some more?
        UNBELIEVABLE_NOW_MAYBE_THOSE_FAR_EASTERN_TRADERS_WON                  = 7730,  -- Unbelievable! Now, maybe those Far Eastern traders won't mix us up into moogle mincemeat! Here's your reward, kupo!
        I_I_M_SPEECHLESS_WE_DIDN_T_THINK                                      = 7731,  -- I-I'm speechless! We didn't think anyone could match wits with that Mithra menace! Here's your reward, kupo!
        THE_SHADOW_OF_THE_THIEF_STILL_LINGERS_WITHIN                          = 7732,  -- The shadow of the thief still lingers within the armor...
        THE_THIEF_S_SHADOW_HAS_ALMOST_DISAPPEARED_COMPLETELY                  = 7733,  -- The thief's shadow has almost disappeared completely.
        SMMMM_N_CXGIQA5D_I1FI7I_L_PB_D_G                                      = 7734,  -- SMMMM%N| CxgIQA5D"i1FI7i L"pB/D`g$ L"pA5D`g$ %j%L8Bc5DKILL7i %S%u%%39i JIfobO7i%hL]%F7i epR%LAjD"i1FI7i AjD"iepOI7i epjPI]h epjQI]h epjRI]h
        KUPO_WHOA_WHOA_THERE_PARDNER_CARE_TO_SADDLE                           = 7739,  -- Kupo-whoa-whoa there, pardner! Care to saddle up and help us rustle up a couple o' wild buffalo? 'Cause we've got a stampede on our hands, I reckon!
        LEND_A_HAND_SKEDADDLE_AWAY_A_STAMPEDE_YOU                             = 7740,  -- Lend a hand? <Skedaddle away.> A stampede, you say? I reckon I will.
        WELL_SIT_DOWN_AND_GRAB_A_SARSAPARILLA_AND                             = 7741,  -- Well, sit down and grab a sarsaparilla, and I'll tell you the tale, kupo. You see, the Mog House Management Union (MHMU) ain't too popular among the townsfolk these days, and they've been talkin' with their wallets by not sendin' too many gold nuggets our way, if you catch my drift.
        BUT_SEEIN_AS_HOW_WE_MOOGLES_ARE_AN                                    = 7742,  -- But seein' as how we moogles are an enterprisin' bunch, we done hatched ourselves a plan, y'hear?
        A_PLAN_WE_CALL_THE_BUFFALO_BONANZA_RANCH                              = 7743,  -- A plan we call... The Buffalo Bonanza Ranch! Yeeeeee-hawww!!!
        RUSTLE_UP_A_HERD_OF_THE_MOST_DARN                                     = 7744,  -- Rustle up a herd of the most darn-tootin' fearsome buffalo from over and yonder, throw a fence around 'em, and you done got yerself the rip-roarin'est dude ranch this side of the Rio Rafeloux, kupo!
        SET_UP_A_SALOON_ON_THE_SIDE_SERVING                                   = 7745,  -- Set up a saloon on the side serving scrumptious buffalo burgers, and you've got contented customers filling our moogle coffers with mucho dinero... Comprende?
        THAT_THERE_WAS_THE_PLAN_PARDNER                                       = 7746,  -- That there was the plan, pardner.
        SO_WE_LASSOED_UP_A_HERD_O_ILL                                         = 7747,  -- So we lassoed up a herd o' ill-tempered buffalo from the mountains up north, and were leadin' our li'l dogies back this-a-way to town...
        AND_THAT_S_WHEN_WE_HIT_A_BIT                                          = 7748,  -- And that's when we hit a bit o' a snag.
        DAGNABBIT_IF_I_KNOW_WHERE_THEY_CAME_FROM                              = 7749,  -- Dagnabbit if I know where they came from, but a swarm of confounded chigoes done showed up!
        NOW_Y_SEE_THESE_BUFFALO_COME_FROM_THE                                 = 7750,  -- Now y'see, these buffalo come from the mountains, and ain't never seen the likes of no chigoes before. They raised a right ruckus, and next thing y'know, we done had a stampede on our hands!
        Y_EVER_SEE_A_STAMPEDIN_BUFFALO_EVEN_OUR                               = 7751,  -- Y'ever see a stampedin' buffalo? Even our moogle hypnosis did 'bout as much good as a poke in the ear with a rusty cattle prod, kupo!
        THAT_S_WHERE_YOU_COME_IN_PARDNER_WHAT                                 = 7752,  -- That's where you come in, pardner. What say you saddle up and help us moogles round up these beasties?
        FOR_EACH_BUFFALO_YOU_CAPTURE_WE_LL_GIVE                               = 7753,  -- For each buffalo you capture, we'll give you one o' these here bovine brands. Collect 'em and mount 'em and you'll be eligible to win a veritable bonanza o' special prizes!
        LOOKS_AT_YOU_WITH_PUPPY_DOG_EYES                                      = 7754,  -- looks at you with puppy-dog eyes...
        NOW_I_D_DO_THIS_MYSELF_AND_SAVE                                       = 7755,  -- Now, I'd do this myself and save y'all the trouble, but jus' look at me... One kick from a stampedin' buffalo and my puny moogle body'd be flung right to the other side o' Vana'diel, I reckon!
        Y_ALL_GOT_NOTHIN_TO_WORRY_BOUT_THOUGH                                 = 7756,  -- Y'all got nothin' to worry 'bout, though. As big and sturdy as you are, I reckon you'd only fly to just over yonder a-ways.
        AND_AS_AN_ADDED_BONUS_YOU_CAN_TRADE                                   = 7757,  -- And as an added bonus, you can trade the bovine brands you've earned for a whole kit 'n caboodle o' Buffalo Bonanza Ranch goods and prizes! Yeeeeee-haw, kupo!
        SO_HOW_S_ABOUT_IT_PARDNER                                             = 7758,  -- So how's about it, pardner?
        GAZES_AT_WITH_A_STEELY_GLINT_IN_HIS                                   = 7759,  -- gazes at % with a steely glint in his eye.
        SADDLE_UP_I_THINK_I_LL_PASS_SURE                                      = 7760,  -- Saddle up? I think I'll pass. Sure. Yeee-haw!
        YIPPIE_KI_YI_YAY_MUCH_OBLIGED_PARDNER                                 = 7761,  -- Yippie ki-yi-yay!!! Much obliged, pardner!
        IF_YOUR_COW_HERDIN_SKILLS_ARE_UP_TO                                   = 7762,  -- If your cow-herdin' skills are up to the task, we'll stamp you some bovine brands on this here sheet.
        ONCE_YOU_VE_RACKED_UP_YOUR_SHARE_O                                    = 7763,  -- Once you've racked up your share o' brands, just mosey back on over here to claim your prizes!
        SO_SHARPEN_YOUR_SPURS_AND_WHEN_YOU_RE                                 = 7764,  -- So sharpen your spurs, and when you're ready, herd up the buffalo and lead them to the moogle cowhand in area [G-9/I-8/G-9/H-9/H-6/I-7], kupo!
        READY_TO_GO_TELL_ME_MORE_ABOUT_THE                                    = 7765,  -- Ready to go? Tell me more about the buffalo. How about some help, pardner? Giddy-up!
        ALL_RIGHT_NOW_GO_RUSTLE_YERSELF_UP_SOME                               = 7766,  -- All right, now go rustle yerself up some buffalo! Yee-haw!
        THE_BIG_BEASTLY_ONES_ARE_THE_BULLS_THE                                = 7767,  -- The big beastly ones are the bulls, the bosses o' the herds. The midsized ones are the mother cows, and the li'l-bittiest ones are the baby calves.
        THE_CALVES_ARE_SWEET_LITTLE_THANGS_DON_T                              = 7768,  -- The calves are sweet little thangs. Don't even have to hypnotize 'em; they'll follow their mother's scent just 'bout anywhere.
        BY_THE_BY_WE_GOT_OURSELVES_A_BOTTLE                                   = 7769,  -- By the by, we got ourselves a bottle o' Eau de Buffalo here. We moogle cowpokes use it to disguise ourselves with the mother buffalo's scent. It's only got # [dose/doses] left, but they're all yours, pardner.
        COURSE_THERE_AIN_T_NO_NEED_TO_FRET                                    = 7770,  -- 'Course, there ain't no need to fret if it runs out. Just brush yerself up against one of the mama cows and you'll get a natural shot of Eau de Buffalo just like that.
        BUT_YOU_D_BEST_BE_CAREFUL_CAUSE_THEY                                  = 7771,  -- But you'd best be careful, 'cause they be some hot-tempered heifers, y'hear? You'll be wantin' to sneak up on them from behind, all careful-like, to avoid their charge.
        AS_FOR_THE_BULLS_I_M_QUAKIN_IN                                        = 7772,  -- As for the bulls, I'm quakin' in my boots just thinkin' 'bout 'em. They're the nastiest, most foul-tempered beasts this ol' cowhand's ever laid eyes upon. You'll be wantin' to steer clear of 'em and stick to roundin' up the cows and calves, kupo.
        AND_DON_T_YOU_BE_FORGETTIN_THAT_THESE                                 = 7773,  -- And don't you be forgettin' that these buffaloes, they always act as a herd, y'hear? So don't go mixin' the herds, or we'll have a right ruckus on our hands.
        AND_YOU_D_BEST_TAKE_CARE_TO_KEEP                                      = 7774,  -- And you'd best take care to keep the chigoes away, too. One li'l bite from them and the buffalo will really start goin' loco, I reckon.
        WITH_THIS_HERE_BOTTLE_O_EAU_DE_BUFFALO                                = 7775,  -- With this here bottle o' Eau de Buffalo, we can make you smell just like one o' the buffalo mamas. It's runnin' low, though, so you'll want to be usin' it wisely, I reckon.
        APPLY_THE_SCENT_NOT_NOW_SURE                                          = 7776,  -- Apply the scent? Not now. Sure.
        A_DAB_OR_TWO_O_BUFFALO_SWEAT_A                                        = 7777,  -- A dab or two o' buffalo sweat, a dab or two o' milk, and...kupo!
        YOU_NOW_SMELL_STRONGLY_OF_BUFFALO                                     = 7778,  -- You now smell strongly of buffalo!
        THERE_REMAINING_DOSE_OF_EAU_DE_BUFFALO                                = 7779,  -- There [is/are] # remaining dose[/s] of Eau de Buffalo.
        SORRY_PARDNER_WE_DONE_EXHAUSTED_OUR_SUPPLY_RECKON                     = 7780,  -- Sorry, pardner, we done exhausted our supply. Reckon you'll just have to do it the hard way...
        THAT_S_A_CRYIN_SHAME_PARDNER                                          = 7781,  -- That's a cryin' shame, pardner.
        IF_N_YOU_CHANGE_YOUR_MIND_JUST_HOLLER                                 = 7782,  -- If'n you change your mind, just holler. We'll be here 'till the cows come home.
        THE_BUFFALO_SCENT_IS_ABOUT_TO_WEAR_OFF                                = 7783,  -- The buffalo scent is about to wear off!
        THE_BUFFALO_SCENT_HAS_WORN_OFF                                        = 7784,  -- The buffalo scent has worn off!
        WELL_I_LL_BE_DARNED_YOU_DONE_RUSTLED                                  = 7785,  -- Well, I'll be darned...you done rustled yerself some buffalo! Giddy on up, 'cause the Buffalo Bonanza Ranch is back in business!
        YOU_GOT_BOVINE_STAMPED_ON_YOUR_YEEE_HAW                               = 7786,  -- You got # bovine [brand/brands] stamped on your %! Yeee-haw!
        TARNATION_IF_YOU_AIN_T_THE_GREATEST_BUFFALO                           = 7787,  -- Tarnation! If you ain't the greatest buffalo herder this ol' cowpoke's ever seen! You've earned yerself some extra brands, pardner.
        YOU_VE_WRANGLED_YERSELF_THE_FOLLOWING_BUFFALO_PARDNER                 = 7788,  -- You've wrangled yerself the following buffalo, pardner:
        ID_7789                                                               = 7789,  -- % %
        ID_7790                                                               = 7790,  -- % %.
        FEELIN_A_BIT_TUCKERED_OUT_YOU_AIN_T                                   = 7791,  -- Feelin' a bit tuckered out? You ain't caught yerself a single buffalo yet.
        AIN_T_GOT_THE_TIME_FOR_THAT_NOW                                       = 7792,  -- Ain't got the time for that now, pardner... We've got a stampede on our hands! We'd be much obliged if you could help us rustle up these buffalo, pardner. Go talk to my compadre by the city gates if yer interested.
        SORRY_PARDNER_BUT_YOU_AIN_T_EARNED_ENOUGH                             = 7793,  -- Sorry, pardner, but you ain't earned enough bovine brands for that.
        HOW_GOES_IT_PARDNER_KEEP_ON_HERDIN_ASK                                = 7794,  -- How goes it, pardner? Keep on herdin'. Ask about the buffalo. Get the mother's scent. Mosey on home.
        SO_LONG_PARDNER_WE_VE_STILL_GOT_OURSELVES                             = 7795,  -- So long, pardner. We've still got ourselves some loose buffalo, so do come back again, y'hear?
        YOU_VE_GOT_YERSELF_BOVINE_PARDNER                                     = 7796,  -- You've got yerself # bovine [brand/brands], pardner.
        TRADE_IN_FOR_A_PRIZE_NOT_NOW_BRANDS                                   = 7797,  -- Trade in for a prize? Not now. % (# brands). % (# brands). % (# brands). % (# brands). % (# brands). % (# brands). % (# brands). % (# brands). % (# brands).
        TRADE_BRANDS_FOR_NO_THANKS_GIDDY_UP                                   = 7798,  -- Trade # brands for %? No thanks. Giddy-up!
        HERE_WE_VE_GOT_A_SPECIAL_BEVERAGE_MADE                                = 7799,  -- Here we've got a special beverage made from buffalo milk, with a dash o' moogle magic. Darned if I know how it works, but one swig o' this and you'll up and transform into any critter you touch. You'll be best buddies with the buffalo in no time, pardner!
        THIS_HERE_S_A_BELT_CRAFTED_FROM_THE                                   = 7800,  -- This here's a belt crafted from the finest buffalo rawhide, soaked in buffalo milk, and left to dry out under the burnin' sun. Got a bit of a foul odor, but it works just like %.
        WITH_THIS_HERE_STYLISH_MANTLE_NOT_ONLY_WILL                           = 7801,  -- With this here stylish mantle, not only will you be the most dashin' cowhand for miles, you'll be able to dodge those blasted buffalo charges a couple'a times, to boot!
        THIS_HERE_S_A_LIMITED_EDITION_BUFFALO_BONANZA                         = 7802,  -- This here's a limited-edition Buffalo Bonanza Ranch cowhorn. It's just a li'l decorative doodad, so it don't make no sound, but word has it that it can make you as rich as a gold mine!
        HANDLE_THIS_HOT_AND_HEAVY_NEW_WAIST_ATTIRE                            = 7803,  -- Handle this hot and heavy new waist attire straight from the heavy horns of the belligerent buffalo Toro himself!
        HANDLE_THIS_HOT_AND_HEAVY_NEW_WAIST_ATTIRE_2                          = 7804,  -- Handle this hot and heavy new waist attire straight from the heavy horns of the belligerent buffalo Miura himself!
        OUR_WONDERFUL_WORKERS_OF_HIDE_HAVE_FASHIONED_THIS                     = 7805,  -- Our wonderful workers of hide have fashioned this fantastic cap that can turn you into a buffalo calf, kupo!
        THIS_CONSPICUOUSLY_CONVENIENT_CAP_WAS_CRAFTED_BY_A                    = 7806,  -- This conspicuously convenient cap was crafted by a masterful Moogle weaver and inexplicably increases the amount of time you can ride your mount, kupo!
        THIS_KEY_WAAS_FOUND_IN_A_SUKEN_SHUP                                   = 7807,  -- This key waas found in a suken shup! Amazing, kupo, but for a limited time only!
        THERE_S_BIG_TROUBLE_KUPO_OUR_MOST_RELIABLE                            = 7808,  -- There's big trouble, kupo! Our most reliable moogle intelligence reports that an odious one-eyed demon known as a Pyracmon is using the Harvest Festival masquerade as a cover and trying to infiltrate the city even as we speak!
        WE_VE_BEEN_TRYING_TO_WARN_PEOPLE_BUT                                  = 7809,  -- We've been trying to warn people, but the bigwigs and guardsmen won't even give us poor little moogles the time of day. But you believe us...don't you, kind adventurer?
        HELP_A_MOOGLE_IN_NEED_BUT_OF_COURSE                                   = 7810,  -- Help a moogle in need? But of course! I think I'll pass.
        SIGH_AND_HERE_I_HAD_A_DEVILISHLY_DELIGHTFUL                           = 7811,  -- <Sigh> And here I had a devilishly delightful Harvest Festival costume handmade just for you... Oh well, looks like it's going back in storage until next year, kupo.
        SPLENDID_KUPO_THE_FIRST_THING_YOU_LL_NEED                             = 7812,  -- Splendid, kupo! The first thing you'll need to do is eliminate the Pyracmon's malevolent minions, the wraith bats!
        THESE_DASTARDLY_CRITTERS_ATTACKED_US_AND_SUCKED_THE                   = 7813,  -- These dastardly critters attacked us and sucked the moogle magic right out of us, kupo! Without it, even the sharpest steel won't so much as scratch the Pyracmon!
        FOR_EACH_BAT_YOU_BANISH_WE_LL_RECOVER                                 = 7814,  -- For each bat you banish, we'll recover some of our magical powers, so lay waste to as many flying foes as you can muster!
        REPORT_BACK_HERE_AFTER_THAT_AND_WE_LL                                 = 7815,  -- Report back here after that, and we'll channel that magic and whip up an incantation that will allow you to vanquish the Pyracmon!
        IN_THE_MEANTIME_I_LL_USE_THE_MEAGER                                   = 7816,  -- In the meantime, I'll use the meager remains of our magic to enchant you with a spell to aid in your battle against the wraith bats, kupo.
        THERE_YOU_GO_NOW_HAVE_AT_THOSE_WINGED                                 = 7817,  -- There you go! Now have at those winged vermin!
        BACK_TO_HELP_US_RID_THE_LAND_OF                                       = 7818,  -- Back to help us rid the land of the vile Pyracmon?
        NEED_HELP_WITH_ANYTHING_JUST_SAY_THE_WORD                             = 7819,  -- Need help with anything? Just say the word, kupo!
        ASK_THE_MOOGLE_FOR_HELP_I_M_FINE                                      = 7820,  -- Ask the moogle for help? I'm fine, thanks. I'm ready to take on the Pyracmon. I give up.
        WOW_LOOKS_LIKE_YOU_MANAGED_TO_RECOVER_OODLES                          = 7821,  -- Wow, looks like you managed to recover oodles of magic from those bats. Oodles, kupo! This should make for a potent incantation indeed!
        MIND_YOU_THIS_ENCHANTMENT_WON_T_LAST_FOREVER                          = 7822,  -- Mind you, this enchantment won't last forever; if it runs out, you'll need to nab some more magic from the bats again. Now go send that ghastly Pyracmon back to the foul depths whence it came!
        WELL_I_M_SURE_A_MIGHTY_ADVENTURER_LIKE                                = 7823,  -- Well, I'm sure a mighty adventurer like you has better things to do than help a poor little Moogle, kupo... Still, the Pyracmon won't rest until he's carried out his nefarious deeds, so do come back if you have a change of heart!
        WOW_YOU_MADE_MINCEMEAT_OUT_OF_THAT_PYRACMON                           = 7824,  -- Wow, you made mincemeat out of that Pyracmon! Just watching the battle sent chills up my little wings, kupo! You're the savior of the town and of all mooglekind!
        THOUGH_IT_MAY_BE_UNWORTHY_OF_A_GREAT                                  = 7825,  -- Though it may be unworthy of a great hero such as yourself, please accept this as a humble token of our moogle gratitude!
        FOR_ALL_WE_KNOW_THE_PYRACMON_IS_STILL                                 = 7826,  -- For all we know, the Pyracmon is still lurking, just waiting for another chance to creep into our ranks. Should it return, please lend us your strength again, kupo!
        BY_THE_BY_HAVE_YOU_HEARD_THAT_SOME                                    = 7827,  -- By the by, have you heard that some eerie and enchanting effulgences have emerged around the realm, kupo?
        EACH_ONE_MUMBLES_AND_MUTTERS_LIKE_A_MISANTHROPIC                      = 7828,  -- Each one mumbles and mutters like a misanthropic miscreant, but pay them no mind. Well now, may mirth and merriment multiply for you during this celebratory season, kupo!
        MY_MY_MY_WHAT_AN_INTRIGUING_SPELL_YOU                                 = 7829,  -- My, my, my... What an intriguing spell you've learned, wayfarer.
        YI_YI_YIKES_ANOTHER_PERNICIOUS_PUPPET_OF_PYRACMON                     = 7830,  -- Yi-yi-yikes! Another pernicious puppet of Pyracmon is poised to pulverize us, kupo!
        PYRACMON_HMM_THAT_MONIKER_MAY_BE_GATHERING_DUST                       = 7831,  -- Pyracmon? Hmm, that moniker may be gathering dust in the corner of my mind, but I do still recall it...possibly from some brittle tome written eons ago.
        IT_S_THE_EXORCIST_WHO_MADE_A_DEAL                                     = 7832,  -- It's the exorcist who made a deal with a de--
        YES_YES_YES_NOW_I_REMEMBER_IT_IS                                      = 7833,  -- Yes, yes, yes...now I remember. It is the name of a youthful yet promising exorcist who formed a perilous pact with a demon, only to become one himself.
        AN_EXORCIST_WHO_HEY_DON_T_PUT_THE                                     = 7834,  -- An exorcist who...hey! Don't put the chocobo before the cart! I don't remember selling my soul to a demon like that ecclesiastical abomination!
        OF_COURSE_BUT_LET_US_NOT_DWELL_ON                                     = 7835,  -- Of course, but let us not dwell on trifling details. You there, adventurer. How about bestowing that boon upon us in a deal of your own? We shall certainly make it worth your while.
        AY_YAI_YAI_I_ARDENTLY_ADVISE_AGAINST_ACCEPTING                        = 7836,  -- Ay yai yai! I ardently advise against accepting an appeal as artful as this, kupo! You sobbed sanguineous streams in your quest to procure this potent magic--you shouldn't just give it away!
        BESTOW_THE_BOON_UPON_YON_BATS_VERILY_NAY                              = 7837,  -- Bestow the boon upon yon bats? Verily. Nay.
        HOW_THOUGHTFUL_OF_YOU_TO_GRACE_US_WITH                                = 7838,  -- How thoughtful of you to grace us with your presence--and your magic--yet again.
        I_VE_NEVER_SEEN_ANYONE_GO_ABOUT_BUSINESS                              = 7839,  -- I've never seen anyone go about business as slow as you! Was your mother a tortoise or something? Anyway, hurry up and give us that magic effect before we die of old age!
        THAT_SPELL_EQUIVALENT_TO_MANDRAGORA_POWER_WE_MUST                     = 7840,  -- That spell...equivalent to # mandragora-power... We must have it.
        WHAT_AN_EXHILARATING_SENSATION_THAT_LAST_BATCH_OF                     = 7841,  -- What an exhilarating sensation! That last batch of magic was as potent as an Ahriman in rut. Should you chance to find yourself with a sorcerous abundance again, we will always welcome you with spread wings.
        I_JUST_KNOW_YOU_RE_HOLDING_OUT_ON                                     = 7842,  -- I just know you're holding out on us, but I'll give you the benefit of the doubt...for now. Next time, try stocking up on more of that magic first.
        I_KNEW_YOU_D_GIVE_US_WHAT_WE                                          = 7843,  -- I knew you'd give us what we needed. Have this in return.
        SORDID_SCRYERS_YOU_JUST_PARTED_WAYS_WITH_ALL                          = 7844,  -- Sordid scryers, %! You just parted ways with all the magnificent magic you managed to muster, kupo!
        WELL_I_SUPPOSE_THERE_S_STILL_SOME_ENHANCING                           = 7845,  -- Well...I suppose there's still some enhancing magic left to help you rout those reprobate wraith bats... Let's get back to business before that brutish Pyracmon can ruin the rest of the Harvest Festival, kupo.
        I_AM_LITERALLY_SPELLBOUND_ADVENTURER_YOUR_CONTRIBUTIONS_HAVE          = 7846,  -- I am literally spellbound, adventurer! Your contributions have surpassed our expectations. Take this as thanks from the bottom of our black hearts.
        IT_TURNS_OUT_THE_ENERGY_CONTAINED_IN_THESE                            = 7847,  -- It turns out the energy contained in these so-called Middle Lands isn't so middling after all. At least it'll be of use once our preparations are underway.
        INDUBITABLY_WHILE_WE_MUST_BID_FAREWELL_TO_THIS                        = 7848,  -- Indubitably. While we must bid farewell to this continent, you can always use that headgear to fly over for a reunion.
        HYAH_HYAH_HYAH_HOW_GULLIBLE_YOU_ARE_YOU                               = 7849,  -- Hyah, hyah, hyah! How gullible you are! You may be well versed in the arts of magic, but your sense of humor still leaves much to be desired.
        UNTIL_NEXT_TIME                                                       = 7850,  -- ...Until next time.
        WHAT_IN_THE_WIDE_WORLD_WAS_WITH_THOSE                                 = 7851,  -- What in the wide world was with those bizarre bats, kupo? I assumed they were allies of that apocalyptic abomination Pyracmon, but it seems my intuition was incorrect...
        BUT_BASED_ON_THE_VARIETY_OF_THEIR_VEXING                              = 7852,  -- But based on the variety of their vexing vocal vibrations, I'd say there were three theurgists controlling those preternatural parasites. All that's beside the point, I suppose. Now we've got to start over from scratch, kupo...
        THIS_TRACE_AMOUNT_LEAVES_OUR_THIRST_FOR_MAGIC                         = 7853,  -- This trace amount leaves our thirst for magic unquenched. The pact cannot be completed unless you return with the ordained measure.
        WHAT_DO_YOU_EXPECT_US_TO_DO_WITH                                      = 7854,  -- What do you expect us to do with these spectral dregs!? This is nothing! Nothing! Don't come back here again until you've obtained an amount decent enough to study!
        YOUR_TOTAL_ONLY_EQUIVALENT_TO_MANDRAGORA_POWER_WE                     = 7855,  -- Your total...only equivalent to # mandragora-power... We require more...
        HOW_DISAPPOINTING_THEN_I_SHALL_TAKE_YOUR_REPLY                        = 7856,  -- How...disappointing. Then I shall take your reply to mean you do not require a certain miraculous artifact we had been saving for you.
        FINE_SEE_IF_I_CARE_IN_FACT_I                                          = 7857,  -- ...Fine! See if I care! In fact, I care so little that I'm gonna put a curse on you for refusing to help us, so there!
        OF_COURSE_YOU_WON_T_NOW_BUT_YOU                                       = 7858,  -- ...Of course you won't now...but you will eventually.
        WHEW_FOR_A_MOMENT_I_WAS_POSITIVELY_PETRIFIED                          = 7859,  -- Whew, for a moment I was positively petrified about your progression on this particular peregrination. Now that that's that, though, let's go pummel Pyracmon, puko! Er, kupo!
        SUCH_ARCANE_POWER_COULD_BE_PUT_TO_MUCH                                = 7860,  -- Such arcane power could be put to much more productive uses than banishing that fairy tale of an exorcist...
        SHOULD_YOU_TAKE_THE_TIME_TO_CHARGE_THAT                               = 7861,  -- Should you take the time to charge that spell once more, we would certainly make it worth your while.
        NOTHING_SEEMS_OUT_OF_THE_ORDINARY_HERE_YET                            = 7862,  -- Nothing seems out of the ordinary here, yet you cannot help but feel ill at ease...
        KUPOPOPO_ACCORDING_TO_MY_OBSERVATIONS_SOME_OCCULT_OBJECT              = 7863,  -- Kupopopo!? According to my observations, some occult object has emerged next to that eerie effulgence. Whatever could it be, kupo?
        A_FIELD_MANUAL_HAS_BEEN_PLACED_HERE_BY                                = 7864,  -- A field manual has been placed here by the Adventurers' Mutual Aid Network (A.M.A.N.). Useful information pertaining to various topics on field operations fills its pages.
        WHAT_WILL_YOU_DO_NOTHING_READ_ABOUT_INDIVIDUAL                        = 7865,  -- What will you do? Nothing. Read about individual training. Review current training regime. Cancel current training regime. Read about elite training. Read about field support.
        WHICH_PAGE_I_VE_CHANGED_MY_MIND_PAGE                                  = 7866,  -- Which page? I've changed my mind. Page 1. Page 2. Page 3. Page 4. Page 5.
